fn read_array(n: i64) -> i64 = {
    let arr: i64 = vec_new();
    for i in 0..n {
        vec_push(arr, read_int());
        ()
    };
    arr
};

fn build_prefix_sums(arr: i64, n: i64) -> i64 = {
    let prefix: i64 = vec_new();
    vec_push(prefix, 0);
    for i in 0..n {
        let prev: i64 = vec_get(prefix, i);
        let curr: i64 = vec_get(arr, i);
        vec_push(prefix, prev + curr);
        ()
    };
    prefix
};

fn range_sum(prefix: i64, l: i64, r: i64) -> i64 = {
    let sum_r: i64 = vec_get(prefix, r + 1);
    let sum_l: i64 = vec_get(prefix, l);
    sum_r - sum_l
};

fn main() -> i64 = {
    let n: i64 = read_int();
    let arr: i64 = read_array(n);
    let prefix: i64 = build_prefix_sums(arr, n);
    let q: i64 = read_int();
    for i in 0..q {
        let l: i64 = read_int();
        let r: i64 = read_int();
        let result: i64 = range_sum(prefix, l, r);
        println(result);
        ()
    };
    vec_free(arr);
    vec_free(prefix);
    0
};
